class Temperatura:
    def __init__(self):
        self._celsius = 0

    @property
    def celsius(self):
        return self._celsius

    @celsius.setter
    def celsius(self, valore):
        if valore < -273.15:
            raise ValueError('Sotto lo zero assoluto!')
        self._celsius = valore

    @property
    def fahrenheit(self):
        return (self._celsius * 9/5) + 32

t = Temperatura()
t.celsius = 25
print(t.fahrenheit)  # 77.0

from abc import ABC, abstractmethod

class Forma(ABC):
    @abstractmethod
    def area(self):
        pass

    @abstractmethod
    def perimetro(self):
        pass

class Rettangolo(Forma):
    def __init__(self, base, altezza):
        self.base = base
        self.altezza = altezza

    def area(self):
        return self.base * self.altezza

    def perimetro(self):
        return 2 * (self.base + self.altezza)

# forma = Forma()  # TypeError!
rett = Rettangolo(5, 3)
print(rett.area())  # 15

